def _server_version() -> str:
    try:
        from importlib.metadata import version

        return version(SERVER_NAME)
    except Exception:
        return "0.0.0"

class InMemoryStorage:
    """Thread-safe in-memory storage for browser instance data."""

    def __init__(self):
        """
        Initialize the in-memory storage.

        self: InMemoryStorage - The storage instance.
        """
        self._lock = threading.RLock()
        self._data: Dict[str, Any] = {"instances": {}}

def add_instance(self, instance_id: str):
    """Add a new browser instance."""
    if instance_id not in self.instance_hooks:
        self.instance_hooks[instance_id] = []

def remove_instance(self, instance_id: str):
    """Remove a browser instance and its hook associations."""
    self.instance_hooks.pop(instance_id, None)

